// ── Calculer date livraison ──
function calculerDateLivraison(delai) {
  if (!delai) return null;

  const valeur = delai.toString().trim();

  // Cas 1 : C'est un nombre seul → ajouter au jour d'aujourd'hui
  // Ex: "2", "7", "15"
  const nombreSeul = valeur.match(/^(\d+)$/);
  if (nombreSeul) {
    const date = new Date();
    date.setDate(date.getDate() + parseInt(nombreSeul[1]));
    return date.toISOString().split('T')[0]; // YYYY-MM-DD
  }

  // Cas 2 : Contient "jour(s)" ou "day(s)" → extraire le nombre
  // Ex: "2 jours", "7 jours", "dans 3 jours", "5 days"
  const avecJours = valeur.match(/(\d+)\s*(jour|day|jours|days)/i);
  if (avecJours) {
    const date = new Date();
    date.setDate(date.getDate() + parseInt(avecJours[1]));
    return date.toISOString().split('T')[0];
  }

  // Cas 3 : Contient "semaine(s)" → multiplier par 7
  // Ex: "2 semaines", "1 semaine"
  const avecSemaines = valeur.match(/(\d+)\s*(semaine|week)/i);
  if (avecSemaines) {
    const date = new Date();
    date.setDate(date.getDate() + parseInt(avecSemaines[1]) * 7);
    return date.toISOString().split('T')[0];
  }

  // Cas 4 : C'est une date directe
  // Ex: "2026-03-15", "15/03/2026", "15-03-2026"
  const dateFormats = [
    /(\d{4})-(\d{2})-(\d{2})/,     // YYYY-MM-DD
    /(\d{2})\/(\d{2})\/(\d{4})/,   // DD/MM/YYYY
    /(\d{2})-(\d{2})-(\d{4})/      // DD-MM-YYYY
  ];

  for (const format of dateFormats) {
    const match = valeur.match(format);
    if (match) {
      let dateStr;
      if (format === dateFormats[0]) {
        dateStr = `${match[1]}-${match[2]}-${match[3]}`;
      } else {
        dateStr = `${match[3]}-${match[2]}-${match[1]}`; // Convertir en YYYY-MM-DD
      }
      const date = new Date(dateStr);
      if (!isNaN(date.getTime())) {
        return date.toISOString().split('T')[0];
      }
    }
  }

  // Cas 5 : Texte non reconnu → retourner null
  console.log(`Délai non reconnu : ${valeur}`);
  return null;
}












