// ── Normaliser disponibilité ──
function normaliserDisponibilite(valeur) {
  if (!valeur) return 'NON_DISPONIBLE';
  const v = valeur.toLowerCase().trim();
  if (v.includes('total') || v === 'totale') return 'TOTALE';
  if (v.includes('partiel') || v === 'partielle') return 'PARTIELLE';
