}

// ── Calculer date livraison ──
function calculerDateLivraison(delai) {
  if (!delai) return null;
  const valeur = delai.toString().trim();

  const nombreSeul = valeur.match(/^(\d+)$/);
  if (nombreSeul) {
    const date = new Date();
    date.setDate(date.getDate() + parseInt(nombreSeul[1]));
    return date.toISOString().split('T')[0];
  }

  const avecJours = valeur.match(/(\d+)\s*(jour|day|jours|days)/i);
  if (avecJours) {
    const date = new Date();
    date.setDate(date.getDate() + parseInt(avecJours[1]));
    return date.toISOString().split('T')[0];
  }

  const avecSemaines = valeur.match(/(\d+)\s*(semaine|week)/i);
  if (avecSemaines) {
    const date = new Date();
    date.setDate(date.getDate() + parseInt(avecSemaines[1]) * 7);
    return date.toISOString().split('T')[0];
  }

  const avecMois = valeur.match(/(\d+)\s*(mois|month)/i);
  if (avecMois) {
    const date = new Date();
    date.setMonth(date.getMonth() + parseInt(avecMois[1]));
    return date.toISOString().split('T')[0];
  }

  if (valeur.toLowerCase().includes('stock')) {
    return new Date().toISOString().split('T')[0];
  }

  const dateISO = valeur.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (dateISO) {
    const date = new Date(`${dateISO[1]}-${dateISO[2]}-${dateISO[3]}`);
    if (!isNaN(date.getTime())) return date.toISOString().split('T')[0];
  }

  const dateFR = valeur.match(/(\d{2})[\/-](\d{2})[\/-](\d{4})/);
  if (dateFR) {
    const date = new Date(`${dateFR[3]}-${dateFR[2]}-${dateFR[1]}`);
    if (!isNaN(date.getTime())) return date.toISOString().split('T')[0];
  }

  return null;
}

